<style>
.booking-subnav{display:flex;flex-wrap:wrap;gap:10px;margin:0 0 14px}.booking-subnav a{display:inline-flex;align-items:center;padding:9px 14px;border:1px solid var(--line);border-radius:999px;text-decoration:none;color:var(--text);background:var(--panel)}.booking-subnav a.active{background:var(--brand);color:#fff;border-color:var(--brand)}
.booking-grid{display:grid;grid-template-columns:1.2fr .8fr;gap:14px}.booking-stack{display:grid;gap:14px}.booking-form-grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:12px}.booking-form-grid .full{grid-column:1/-1}.booking-card-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:12px}.booking-day-grid{display:grid;grid-template-columns:repeat(7,minmax(0,1fr));gap:12px}.booking-day-grid--day{grid-template-columns:minmax(0,1fr)}.booking-day{border:1px solid var(--line);border-radius:16px;background:var(--panel);padding:12px;min-height:220px}.booking-booking{border:1px solid var(--line);border-radius:14px;padding:10px;background:rgba(37,99,235,.05);display:grid;gap:6px}.booking-inline{display:flex;flex-wrap:wrap;gap:8px;align-items:center}.booking-widget-note{border:1px dashed var(--line);border-radius:14px;padding:12px;background:rgba(15,23,42,.02)}
.booking-page-grid{display:grid;grid-template-columns:minmax(0,1.1fr) minmax(320px,.9fr);gap:14px}.booking-list{display:grid;gap:10px}.booking-list-card{display:grid;gap:8px;padding:12px;border:1px solid var(--line);border-radius:14px;background:var(--panel);color:inherit;text-decoration:none}.booking-list-card.is-active{border-color:var(--brand);box-shadow:0 0 0 1px rgba(37,99,235,.15)}.booking-list-card.is-requested{background:rgba(245,158,11,.08)}.booking-service-meta{display:flex;flex-wrap:wrap;gap:8px;color:var(--muted)}.booking-service-meta .status-pill{font-size:12px}.booking-detail-card{display:grid;gap:12px}.booking-section{display:grid;gap:10px;padding:14px;border:1px solid var(--line);border-radius:16px;background:var(--panel)}.booking-section-title{margin:0;font-size:15px;font-weight:700}.booking-helper{color:var(--muted);font-size:13px;line-height:1.45}.booking-stat-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(120px,1fr));gap:10px}.booking-stat{display:grid;gap:4px;padding:10px 12px;border:1px solid var(--line);border-radius:12px;background:rgba(15,23,42,.02)}.booking-stat strong{font-size:18px}.booking-form-actions{display:flex;flex-wrap:wrap;gap:8px}.booking-nav-tabs{display:flex;flex-wrap:wrap;gap:8px}.booking-nav-tabs a{padding:8px 12px;border:1px solid var(--line);border-radius:999px;text-decoration:none;color:var(--text)}.booking-nav-tabs a.active{background:var(--brand);color:#fff;border-color:var(--brand)}
.booking-grid--settings{grid-template-columns:minmax(0,1fr) minmax(320px,.95fr)}.booking-grid--availability{grid-template-columns:minmax(0,1fr) minmax(360px,.95fr)}.booking-inline--between{justify-content:space-between}.booking-checkbox{display:flex;gap:10px;align-items:flex-start}.booking-checkbox small{display:block;color:var(--muted);margin-top:2px}.booking-checkbox--inline{align-items:center}.booking-management-stats{margin:0 0 14px}.booking-log-table{width:100%;border-collapse:collapse}.booking-log-table th,.booking-log-table td{padding:10px 8px;border-bottom:1px solid var(--line);vertical-align:top}.booking-log-table th{text-align:left;color:var(--muted);font-size:12px;text-transform:uppercase;letter-spacing:.08em}.booking-log-table code{font-size:12px}.booking-log-table .status-pill{font-size:12px}.booking-event-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:8px}
@media (max-width: 1100px){.booking-grid,.booking-day-grid,.booking-form-grid,.booking-page-grid{grid-template-columns:1fr}}
</style>
